import React from 'react';
import { useParams } from 'react-router-dom';

const caseData = {
  1: {
    title: "Too Good to Be True? It Was.",
    happened: "15-year-old Mia saw a TikTok post promising \"£200 in 2 hours – just help us boost some online sales!\" All she had to do was pay £50 upfront for a \"starter task,\" and she'd get it all back.\n\nYou guessed it—Mia paid, and then… crickets 🦗. The account blocked her. The \"company\" vanished. She had just lost her birthday money. 😭",
    wrong: "Scammers used flashy social media ads to bait teens. They used fake logos, fake reviews, and \"too-easy\" promises to make it feel safe. But once you pay, it's game over.\n\nVodafone says nearly 1 million UK kids were scammed online last year—on platforms like TikTok, Instagram, and Snapchat.",
    advice: "If it sounds too perfect, it probably is\nNever pay upfront to \"get paid\"\nDon't trust random DMs offering cash 💸\nIf you're scammed, talk to an adult, and report it to Action Fraud\nYou're not dumb. Scammers are just really good at what they do"
  },
  2: {
    title: "Oops… That Wasn't What I Thought!",
    happened: "16‑year‑old Nathan was chatting online late one night when he got nudged to send a \"private selfie.\" He thought it was between him and a friend—until the next thing he knew, someone was threatening to blast it to his whole contact list 💥—unless he paid £50.",
    wrong: "Because he was! After admitting it to his parents, Nathan felt like he'd made the worst mistake ever. But his folks kept their cool and reassured him it wasn't the end of the world.",
    advice: "You're not in trouble—snapping a pic doesn't make you a bad person.\nIf someone threatens you over it—don't pay and don't panic.\nTell someone you trust—parents, CEOP, school—story's easier when shared.\nThis kind of thing happens to loads of teens, and the key is talking it out ❤️"
  },
  3: {
    title: "Not Your Average Snapchat Friend!",
    happened: "17-year-old Ben thought he was chatting with a cute girl on Snapchat. She sent flirty messages and asked him to \"trust her\" with a private video. Ben nervously sent one... and boom 💥—the 'girl' disappeared, replaced by someone demanding £100 or they'd send the video to his entire contact list.\n\nTurns out, it wasn't a girl at all—it was a scam gang using deepfake profiles to trick boys into sharing private stuff, then blackmailing them.",
    wrong: "Ben didn't know that anyone can pretend to be someone else online. The scammers were pros—they used fake photos, AI voices, even video filters.",
    advice: "Never send personal or private content online—even if it feels \"safe\"\nIf you're blackmailed, don't pay and don't panic\nTell a trusted adult or report to CEOP or Childline\nYou're not alone, and you're not stupid—it happens to many teens. The important thing is to speak up 💪"
  },
  4: {
    title: "Wait... Was That Even a Real Investment?",
    happened: "15-year-old Mia saw a \"Get Rich Fast 💸\" video on TikTok. A cool-looking guy promised he could double her money in two hours—just send £50 via bank transfer. Easy, right? She sent it… and then? Boom. He vanished like a ghost 👻.\n\nTurns out, she wasn't alone. A UK-wide survey found that nearly 3 in 10 young people (13–21) had been scammed online—fake giveaways, investment fraud, even people pretending to be friends or teachers asking for money!",
    wrong: "Scammers don't wear ski masks—they slide into your DMs, act cool, and build trust. They often use platforms like Instagram, Snapchat, or WhatsApp, and sound just like real people.",
    advice: "Be suspicious of \"too good to be true\" deals\nNever send money to online strangers—even if they seem trustworthy\nDouble check with a real adult or friend before you click or transfer\nReport it to Action Fraud or tell someone you trust\nYou're smart. These scams are sneaky—that’s why we talk about them 💬"
  }
};

export default function CaseDetail() {
  const { id } = useParams();
  const data = caseData[id];

  if (!data) return <div style={{ padding: '2em' }}><h2>Case not found</h2></div>;

  return (
    <div style={styles.container}>
      <h2 style={styles.title}>{data.title}</h2>

      <section>
        <h3>📍 What Happened?</h3>
        <p>{data.happened}</p>
      </section>

      <section>
        <h3>🎣 What Went Wrong?</h3>
        <p>{data.wrong}</p>
      </section>

      <section>
        <h3>✅ What Can You Do?</h3>
        <ul>
          {data.advice.split('\n').map((item, idx) => (
            <li key={idx}>{item}</li>
          ))}
        </ul>
      </section>
    </div>
  );
}

const styles = {
  container: {
    padding: '2em',
    maxWidth: '800px',
    margin: '0 auto',
    fontFamily: 'Arial, sans-serif'
  },
  title: {
    marginBottom: '1em',
    fontSize: '1.8em',
    color: '#333'
  }
};
